const entries = $('Get Today\'s Entries').all().map(i => i.json);
const goals = $('Get Active Goals').all().map(i => i.json);

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Group entries by impact level
const high = entries.filter(e => e.impact_level === 'high' || e.impact_level === 'critical');
const medium = entries.filter(e => e.impact_level === 'medium');
const low = entries.filter(e => e.impact_level === 'low' || !e.impact_level);

// Count goals with progress
const goalsProgressed = goals.filter(g => g.current_value > 0).length;

// Generate HTML
let html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; line-height: 1.6; color: #1e293b; max-width: 600px; margin: 0 auto; padding: 20px; }
    .header { border-bottom: 2px solid #3b82f6; padding-bottom: 16px; margin-bottom: 24px; }
    .header h1 { margin: 0; font-size: 24px; }
    .stats { display: flex; justify-content: space-around; background: #f1f5f9; padding: 16px; border-radius: 8px; margin-bottom: 24px; }
    .stat { text-align: center; }
    .stat-value { font-size: 24px; font-weight: 700; color: #3b82f6; }
    .stat-label { font-size: 12px; color: #64748b; }
    .section h2 { font-size: 18px; border-bottom: 1px solid #e2e8f0; padding-bottom: 8px; }
    .impact-group h3 { font-size: 14px; color: #64748b; text-transform: uppercase; }
    .entry { padding: 12px 16px; margin: 8px 0; background: #f8fafc; border-radius: 6px; }
    .entry.high { border-left: 4px solid #22c55e; }
    .entry.medium { border-left: 4px solid #eab308; }
    .entry.low { border-left: 4px solid #94a3b8; }
    .entry-title { font-weight: 600; }
    .entry-category { font-size: 11px; color: #64748b; background: #e2e8f0; padding: 2px 8px; border-radius: 4px; margin-left: 8px; }
    .entry-desc { font-size: 14px; color: #475569; margin-top: 4px; }
    .goal { padding: 12px 0; border-bottom: 1px solid #e2e8f0; }
    .goal-title { font-weight: 600; }
    .goal-meta { font-size: 12px; color: #64748b; }
    .progress-bar { height: 8px; background: #e2e8f0; border-radius: 4px; margin: 8px 0; }
    .progress-fill { height: 100%; background: linear-gradient(90deg, #3b82f6, #06b6d4); border-radius: 4px; }
    .footer { margin-top: 32px; text-align: center; font-size: 12px; color: #94a3b8; }
  </style>
</head>
<body>
  <div class="header">
    <h1>Daily Progress</h1>
    <div style="color: #64748b;">${today}</div>
  </div>

  <div class="stats">
    <div class="stat"><div class="stat-value">${entries.length}</div><div class="stat-label">Accomplishments</div></div>
    <div class="stat"><div class="stat-value">${high.length}</div><div class="stat-label">High Impact</div></div>
    <div class="stat"><div class="stat-value">${goalsProgressed}</div><div class="stat-label">Goals Progressed</div></div>
  </div>

  <div class="section">
    <h2>Today's Accomplishments</h2>
`;

if (high.length > 0) {
  html += '<div class="impact-group"><h3>High Impact</h3>';
  high.forEach(e => {
    html += `<div class="entry high"><div class="entry-title">${e.title}<span class="entry-category">${e.impact_category}</span></div>${e.description ? `<div class="entry-desc">${e.description}</div>` : ''}</div>`;
  });
  html += '</div>';
}

if (medium.length > 0) {
  html += '<div class="impact-group"><h3>Medium Impact</h3>';
  medium.forEach(e => {
    html += `<div class="entry medium"><div class="entry-title">${e.title}<span class="entry-category">${e.impact_category}</span></div>${e.description ? `<div class="entry-desc">${e.description}</div>` : ''}</div>`;
  });
  html += '</div>';
}

if (low.length > 0) {
  html += '<div class="impact-group"><h3>Low Impact</h3>';
  low.forEach(e => {
    html += `<div class="entry low"><div class="entry-title">${e.title}<span class="entry-category">${e.impact_category}</span></div></div>`;
  });
  html += '</div>';
}

html += '</div><div class="section"><h2>Goal Progress</h2>';

goals.forEach(g => {
  const progress = g.progress_percent || 0;
  html += `
    <div class="goal">
      <div class="goal-title">${g.title}</div>
      <div class="goal-meta">${g.horizon} | ${g.days_remaining} days remaining</div>
      <div class="progress-bar"><div class="progress-fill" style="width: ${progress}%"></div></div>
      <div class="goal-meta">${progress}% complete${g.target_value ? ` (${g.current_value}/${g.target_value})` : ''}</div>
    </div>
  `;
});

html += `
  </div>
  <div class="footer">
    Generated by IAML Business OS
  </div>
</body>
</html>
`;

return {
  subject: `Daily Progress: ${today}`,
  html,
  entryCount: entries.length,
  highImpactCount: high.length,
  goalsCount: goals.length
};
